function cssRule(selector) {
  const matches = [...readerStyles.matchAll(/([^{}]+)\{[^}]+\}/g)]
    .filter((match) => match[1].split(',').map((part) => part.trim()).includes(selector));
  return matches.at(-1)?.[0] ?? '';
}

function firstCssRule(selector) {
  const matches = [...readerStyles.matchAll(/([^{}]+)\{[^}]+\}/g)]
    .filter((match) => match[1].split(',').map((part) => part.trim()).includes(selector));
  return matches.at(0)?.[0] ?? '';
}

