assert.match(readerPageMeasurementControllerSource, /settings\.layoutMode === 'flow'\s*\?\s*'single'\s*:\s*resolveReaderEffectivePageMode/, 'flow layout width must be resolved as a single reading column even when page mode is configured as double');
assert.match(readerPageMeasurementControllerSource, /const effectivePageWidth = resolveReaderSpreadPageWidth\(visualSettings\.pageWidth, availableReaderWidth, resolvedPageMode, visualSettings\.pageGap\)/, 'rendered page width must account for two pages and their gap in double-page mode');
assert.match(readerPageMeasurementControllerSource, /const pageWidth = resolveReaderSpreadPageWidth\(settings\.pageWidth, availableReaderWidth, resolvedPageMode, settings\.pageGap\)/, 'page measurement cache width must match the rendered double-page width');

